@scheduler.task(base=BaseTask, bind=True)
def fetch_m023_api(self, sensor_ids, date_begin, date_end, **kwargs):
    try:
        sensors = Sensor.objects.filter(
            id__in=sensor_ids, model__name="enedis", has_consent=True
        ).prefetch_related("data_type", "model")
    except Sensor.DoesNotExist:
        return

    if not sensors.exists():
        logger.warning(f"Sensors {sensor_ids} have no consent")
        return

    enedis = Enedis()
    enedis.fetch_multiple_measure_details_async(
        list(sensors),
        date_begin,
        date_end,
        push_to_sdata=True,
    )


@scheduler.task(base=BaseTask, bind=True)
def correct_data(self, **kwargs):
    now = arrow.utcnow()
    begin = now.shift(days=-15)
    call_command(
        "correct_data",
        "--data_type=electricity",
        f"--date_begin={begin.format('YYYY-MM-DD')}",
        f"--date_end={now.format('YYYY-MM-DD')}",
    )
    call_command(
        "correct_data",
        "--data_type=gas",
        f"--date_begin={begin.format('YYYY-MM-DD')}",
        f"--date_end={now.format('YYYY-MM-DD')}",
    )


