@scheduler.task(base=BaseTask, bind=True)
def compute_and_set_references(
    self,
    sensors_ids,
    building_to_date_begin,
    recompute=False,
    from_2020=False,
    ignore_last_year=False,
    before_date=None,
    replace=False,
    years=[],
    **kwargs,
):
    """Compute reference for all sensors of a building by getting the sum of each consumption for each year
    and defining which year has the highest sum consumption

    Args:
        sensors (array): All the sensors of a building with is_terdecree
    """

    util_compute_and_set_references(
        sensors_ids,
        building_to_date_begin,
        recompute=recompute,
        from_2020=from_2020,
        ignore_last_year=ignore_last_year,
        before_date=before_date,
        computed_datas=None,
        replace=replace,
        years=years,
        **kwargs,
    )
